fn getFieldNames(comptime T: type) []const []const u8 {
    const fields = @typeInfo(T).@"struct".fields;
    var names: [fields.len][]const u8 = undefined;
    for (fields, 0..) |field, i| {
        names[i] = field.name;
    }
    return &names;
}

const ValidationError = error{ EmptyString, InvalidLength };

fn validateString(s: []const u8, min_len: usize) ValidationError!void {
    if (s.len == 0) return error.EmptyString;
    if (s.len < min_len) return error.InvalidLength;
}
